class Playground {
    async run(inputs) {
        const n = parseInt(inputs[0]) || 8;
        const unionString = inputs[1] || "";

        // Initialize structures
        this.uf.init(n);
        this.vars.init([
            ["Status", "Initialized"],
            ["Operation", "None"],
            ["Result", "N/A"]
        ]);

        this.log(`Initialized Union Find with ${n} elements (0 to ${n - 1}).`);
        await this.await();

        // Parse input pairs
        const pairs = unionString.split(',')
            .map(p => p.trim().split('-').map(Number))
            .filter(p => p.length === 2 && !isNaN(p[0]) && !isNaN(p[1]));

        for (const [u, v] of pairs) {
            this.vars.put("Status", "Processing");
            this.vars.put("Operation", `union(${u}, ${v})`);

            this.log(`Starting Union operation for nodes ${u} and ${v}`);
            this.uf.highlightNode(u, "var(--primary)");
            this.uf.highlightNode(v, "var(--primary)");
            await this.await();

            // Step 1: Find roots
            this.log(`Finding root of element ${u}...`);
            const rootU = this.uf.find(u);
            this.uf.highlightNode(rootU, "orange");
            this.vars.put("Result", `root(${u}) = ${rootU}`);
            await this.await();

            this.log(`Finding root of element ${v}...`);
            const rootV = this.uf.find(v);
            this.uf.highlightNode(rootV, "orange");
            this.vars.put("Result", `root(${v}) = ${rootV}`);
            await this.await();

            // Step 2: Union if roots are different
            if (rootU !== rootV) {
                this.log(`Roots are different (${rootU} != ${rootV}). Merging sets.`);
                this.uf.union(u, v);
                this.vars.put("Result", "Sets Merged");
                await this.await();
            } else {
                this.log(`Roots are the same (${rootU}). Nodes are already in the same set.`);
                this.vars.put("Result", "Already in same set");
                await this.await();
            }

            // Cleanup highlights for next iteration
            this.uf.highlightNode(u, null);
            this.uf.highlightNode(v, null);
            this.uf.highlightNode(rootU, null);
            this.uf.highlightNode(rootV, null);
            this.vars.put("Operation", "Waiting");
            await this.await();
        }

        this.vars.put("Status", "Finished");
        this.vars.put("Operation", "None");
        this.log("All union operations completed.");

        // Final state representation
        const parents = this.uf.getValues();
        return {
            message: "Union Find completed",
            parentArray: parents
        };
    }
}
